('additional-maths:7-4-reduction-to-linear-form:mcq:eed3ed3f', 'additional-maths', 'additional-maths:7-4-reduction-to-linear-form', '7.4 Reduction to Linear Form', 'mcq', 'mcq', 1, '{"question": "Taking logs of \\( y = ka^x \\) gives which linear equation?", "options": ["\\( \\log y = (\\log a)x + \\log k \\)", "\\( \\log y = x\\log(ka) \\)", "\\( \\log y = a\\log x + \\log k \\)", "\\( \\log y = (\\log k)x + \\log a \\)"]}'::jsonb, '{"answer": 0, "explain": "Product then power law: \\( \\log y = \\log k + x\\log a = (\\log a)x + \\log k \\)."}'::jsonb),
('additional-maths:7-4-reduction-to-linear-form:mcq:04191a97', 'additional-maths', 'additional-maths:7-4-reduction-to-linear-form', '7.4 Reduction to Linear Form', 'mcq', 'mcq', 1, '{"question": "For \\( y = kx^n \\), what do you plot to obtain a straight line?", "options": ["\\( \\log y \\) against \\( \\log x \\)", "\\( \\log y \\) against \\( x \\)", "\\( y \\) against \\( \\log x \\)", "\\( x \\) against \\( y \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log y = n\\log x + \\log k \\), so plot \\( \\log y \\) vs \\( \\log x \\)."}'::jsonb),
('additional-maths:7-4-reduction-to-linear-form:mcq:43edfa74', 'additional-maths', 'additional-maths:7-4-reduction-to-linear-form', '7.4 Reduction to Linear Form', 'mcq', 'mcq', 1, '{"question": "You plot \\( \\log y \\) against \\( x \\) for \\( y = ka^x \\) and find the gradient is \\( 0.6 \\). What is \\( a \\)?", "options": ["\\( 10^{0.6} \\approx 4.0 \\)", "\\( 0.6 \\)", "\\( \\log 0.6 \\)", "\\( 6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Gradient \\( = \\log a \\), so anti-log: \\( a = 10^{0.6} \\approx 4.0 \\). Do not quote the gradient itself."}'::jsonb),
