('additional-maths:7-4-reduction-to-linear-form:mcq:75b887c0', 'additional-maths', 'additional-maths:7-4-reduction-to-linear-form', '7.4 Reduction to Linear Form', 'mcq', 'mcq', 1, '{"question": "Which is the correct expansion of \\( \\log(ka^n) \\)?", "options": ["\\( \\log k + n\\log a \\)", "\\( n\\log(ka) \\)", "\\( n\\log k + n\\log a \\)", "\\( \\log k \\times n\\log a \\)"]}'::jsonb, '{"answer": 0, "explain": "Product law then power law. The classic 2024 trap is writing \\( n\\log(ka) \\)."}'::jsonb),
