('additional-maths:7-4-reduction-to-linear-form:fib:6b25245d', 'additional-maths', 'additional-maths:7-4-reduction-to-linear-form', '7.4 Reduction to Linear Form', 'fib', 'fib', 1, '{"question": "The gradient you read off is really \\( \\log a \\), so to recover \\( a \\) you must ___B1___ it, giving \\( a = 10 \\) to that power.", "blankOptions": {"B1": ["n", "anti-log", "non-linear", "m"]}}'::jsonb, '{"blanks": {"B1": "anti-log"}}'::jsonb),
